import{bV as s,aL as i,u as t,G as e}from"./chunks/framework.D_inzUUb.js";const k=JSON.parse('{"title":"KMS 激活 Windows 与 Office","description":"","frontmatter":{"title":"KMS 激活 Windows 与 Office","date":"2019-06-13T00:00:00.000Z","categories":["Windows"],"tags":["KMS","Windows","Office","激活"]},"headers":[],"relativePath":"posts/201906/13-kms.md","filePath":"posts/201906/13-kms.md","lastUpdated":1777605256000}'),l={name:"posts/201906/13-kms.md"};function r(n,a,o,h,d,p){return i(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="kms-激活-windows-与-office" tabindex="-1">KMS 激活 Windows 与 Office <a class="header-anchor" href="#kms-激活-windows-与-office" aria-label="Permalink to &quot;KMS 激活 Windows 与 Office&quot;">​</a></h1><blockquote><p>整合自 <a href="https://github.com/aiastia/note/issues/60" target="_blank" rel="noreferrer">#60</a>、<a href="https://github.com/aiastia/note/issues/61" target="_blank" rel="noreferrer">#61</a>、<a href="https://github.com/aiastia/note/issues/73" target="_blank" rel="noreferrer">#73</a></p></blockquote><h2 id="slmgr-vbs-命令速查表" tabindex="-1">slmgr.vbs 命令速查表 <a class="header-anchor" href="#slmgr-vbs-命令速查表" aria-label="Permalink to &quot;slmgr.vbs 命令速查表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>功能说明</th></tr></thead><tbody><tr><td><code>slmgr.vbs -dli</code></td><td>显示操作系统版本、部分产品密钥、许可证状态</td></tr><tr><td><code>slmgr.vbs -dlv</code></td><td>最详尽的激活信息（激活ID、安装ID、激活截止日期等）</td></tr><tr><td><code>slmgr.vbs -xpr</code></td><td>查看是否彻底激活 / 激活过期时间</td></tr><tr><td><code>slmgr.vbs -ipk &lt;密钥&gt;</code></td><td>安装产品密钥</td></tr><tr><td><code>slmgr.vbs -upk</code></td><td>卸载产品密钥</td></tr><tr><td><code>slmgr.vbs -ato</code></td><td>激活 Windows</td></tr><tr><td><code>slmgr.vbs -skms &lt;服务器&gt;</code></td><td>设置 KMS 服务器与端口</td></tr><tr><td><code>slmgr.vbs -ckms</code></td><td>清除所使用的 KMS 服务器信息</td></tr><tr><td><code>winver</code></td><td>显示操作系统版本信息</td></tr></tbody></table><h2 id="windows-kms-激活步骤" tabindex="-1">Windows KMS 激活步骤 <a class="header-anchor" href="#windows-kms-激活步骤" aria-label="Permalink to &quot;Windows KMS 激活步骤&quot;">​</a></h2><p>以管理员身份运行 cmd，按以下步骤操作：</p><h3 id="_1-卸载之前的密钥" tabindex="-1">1. 卸载之前的密钥 <a class="header-anchor" href="#_1-卸载之前的密钥" aria-label="Permalink to &quot;1. 卸载之前的密钥&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slmgr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /upk</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slmgr.vbs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /upk</span></span></code></pre></div><p>弹出窗口显示「成功地卸载了产品密钥」。如果提示找不到密钥，不用管，直接跳到下一步。</p><h3 id="_2-安装产品密钥" tabindex="-1">2. 安装产品密钥 <a class="header-anchor" href="#_2-安装产品密钥" aria-label="Permalink to &quot;2. 安装产品密钥&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slmgr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /ipk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> W269N-WFGWX-YVC9B-4J6C9-T83GX</span></span></code></pre></div><p>弹出窗口显示「成功地安装了产品密钥」。</p><h3 id="_3-设置密钥管理服务器" tabindex="-1">3. 设置密钥管理服务器 <a class="header-anchor" href="#_3-设置密钥管理服务器" aria-label="Permalink to &quot;3. 设置密钥管理服务器&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slmgr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /skms</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kms.cangshui.net</span></span></code></pre></div><p>弹出窗口提示「密钥管理服务计算机名称成功地设置为 kms.cangshui.net」。网络上非常多这种 KMS 服务器。</p><h3 id="_4-激活产品" tabindex="-1">4. 激活产品 <a class="header-anchor" href="#_4-激活产品" aria-label="Permalink to &quot;4. 激活产品&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slmgr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /ato</span></span></code></pre></div><p>弹出窗口提示「成功地激活了产品」。</p><h3 id="_5-查看激活信息" tabindex="-1">5. 查看激活信息 <a class="header-anchor" href="#_5-查看激活信息" aria-label="Permalink to &quot;5. 查看激活信息&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看激活过期时间</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slmgr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /xpr</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看详细激活信息</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slmgr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dlv</span></span></code></pre></div><h2 id="office-激活-office-tool-plus" tabindex="-1">Office 激活（Office Tool Plus） <a class="header-anchor" href="#office-激活-office-tool-plus" aria-label="Permalink to &quot;Office 激活（Office Tool Plus）&quot;">​</a></h2><p>Office Tool Plus 是一款 Office 部署与激活工具，支持通过 KMS 方式激活 Office。</p><h3 id="重要说明" tabindex="-1">重要说明 <a class="header-anchor" href="#重要说明" aria-label="Permalink to &quot;重要说明&quot;">​</a></h3><ul><li>KMS 只能激活<strong>批量版 (Volume)</strong> 许可证，不能激活零售版 (Retail)</li><li>激活完成后所有功能正常使用，不存在不能登录账户的说法</li><li>激活后系统会 <strong>7 天自动续期一次</strong>，不会 180 天后到期（前提是 KMS 服务器和网络正常）</li><li>激活出问题时请先检查步骤是否有误，<strong>不要盲目重装 Office</strong></li><li>MSDN 上留存的 Office 安装包太旧，建议从 Office Tool Plus 重新下载</li></ul><h3 id="使用步骤" tabindex="-1">使用步骤 <a class="header-anchor" href="#使用步骤" aria-label="Permalink to &quot;使用步骤&quot;">​</a></h3><ol><li>打开 Office Tool Plus</li><li>进入「激活」页面</li><li>点击「清除激活信息」</li><li>选择 KMS 激活方式（自动或手动均可）</li><li>设置 KMS 服务器地址，点击激活</li></ol><h2 id="常用-gvlk-密钥" tabindex="-1">常用 GVLK 密钥 <a class="header-anchor" href="#常用-gvlk-密钥" aria-label="Permalink to &quot;常用 GVLK 密钥&quot;">​</a></h2><p>不同版本的 Windows / Office 需要使用不同的 KMS 客户端安装密钥（GVLK），上文使用的 <code>W269N-WFGWX-YVC9B-4J6C9-T83GX</code> 适用于 Windows 10/11 Pro。</p><p>更多版本的密钥请查看微软官方文档：</p><ul><li><strong>Windows</strong>：<a href="https://learn.microsoft.com/zh-cn/windows-server/get-started/kms-client-activation-keys" target="_blank" rel="noreferrer">KMS 客户端安装密钥</a></li><li><strong>Office</strong>：<a href="https://learn.microsoft.com/zh-cn/DeployOffice/vlactivation/gvlks" target="_blank" rel="noreferrer">Office GVLK 密钥</a></li></ul><h2 id="零售版转-vol-版" tabindex="-1">零售版转 VOL 版 <a class="header-anchor" href="#零售版转-vol-版" aria-label="Permalink to &quot;零售版转 VOL 版&quot;">​</a></h2><blockquote><p>来源：<a href="https://github.com/aiastia/note/issues/46" target="_blank" rel="noreferrer">#46</a></p></blockquote><p>Win7 零售版及之后版本可以转换为 VOL（批量授权）版，从而支持 KMS 激活。</p><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li><strong>查看当前系统版本</strong>（管理员 CMD）：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wmic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> os</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> caption</span></span></code></pre></div><ol start="2"><li><p><strong>查找对应版本的 GVLK 密钥</strong>：</p><p><a href="https://docs.microsoft.com/zh-cn/windows-server/get-started/kmsclientkeys" target="_blank" rel="noreferrer">微软官方 KMS 客户端密钥</a></p></li><li><p><strong>安装 GVLK 密钥</strong>（管理员 CMD）：</p></li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slmgr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /ipk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xxxxx-xxxxx-xxxxx-xxxxx</span></span></code></pre></div><ol start="4"><li><strong>重启电脑</strong>，转换即完成。</li></ol><p>适用系统：Win7 ~ Win10。</p><hr><h2 id="kms-服务器" tabindex="-1">KMS 服务器 <a class="header-anchor" href="#kms-服务器" aria-label="Permalink to &quot;KMS 服务器&quot;">​</a></h2><p>网络上有很多公开的 KMS 服务器，可参考：</p><ul><li><a href="https://www.coolhub.top/archives/14/comment-page-8" target="_blank" rel="noreferrer">KMS 服务器合集 - CoolHub</a></li></ul><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="https://learn.microsoft.com/zh-cn/windows-server/get-started/kms-client-activation-keys" target="_blank" rel="noreferrer">Windows KMS 客户端激活密钥</a></li><li><a href="https://learn.microsoft.com/zh-cn/DeployOffice/vlactivation/gvlks" target="_blank" rel="noreferrer">Office GVLK 密钥</a></li><li><a href="https://otp.landian.vip/" target="_blank" rel="noreferrer">Office Tool Plus 官网</a></li><li><a href="https://otp.landian.vip/help/" target="_blank" rel="noreferrer">Office Tool Plus 激活教程</a></li></ul>`,46)])])}const g=s(l,[["render",r]]);export{k as __pageData,g as default};
